INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0554d78a-3a2f-4827-899f-980ac632cee9', $q$Cloud-based charting$q$, $q$Browser-accessible patient charting with customizable templates for common outpatient visit types, eliminating the need for on-premise servers.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0554d78a-3a2f-4827-899f-980ac632cee9', $q$E-prescribing$q$, $q$Electronic prescription routing to pharmacies, including support for prescribing controlled substances where state and DEA requirements are met.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0554d78a-3a2f-4827-899f-980ac632cee9', $q$Scheduling$q$, $q$Appointment scheduling tools that let front-office staff manage provider calendars and patient visits across a practice.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0554d78a-3a2f-4827-899f-980ac632cee9', $q$Lab and imaging orders$q$, $q$Electronic ordering and results integration for labs and imaging, keeping diagnostic data connected to the patient chart.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0554d78a-3a2f-4827-899f-980ac632cee9', $q$Patient portal$q$, $q$A patient-facing portal for basic record access and communication between visits.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0554d78a-3a2f-4827-899f-980ac632cee9', $q$Billing and claims integration$q$, $q$Connections to billing workflows and clearinghouse partners to support claims submission for outpatient practices.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0554d78a-3a2f-4827-899f-980ac632cee9', $q$Quality measure reporting$q$, $q$Reporting tools that help practices track and document quality measures relevant to value-based care programs.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0554d78a-3a2f-4827-899f-980ac632cee9', $q$Interoperability$q$, $q$Health information exchange connections, supported by Veradigm's broader interoperability network, to help share patient records across care settings.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0554d78a-3a2f-4827-899f-980ac632cee9', $q$Charting templates$q$, $q$Specialty-oriented note templates that can be adapted to a practice's preferred documentation style.$q$, 8);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0554d78a-3a2f-4827-899f-980ac632cee9', $q$Browser-based access removes the need for on-site servers or heavy IT management$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0554d78a-3a2f-4827-899f-980ac632cee9', $q$Familiar charting and note structures ease the transition from paper records$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0554d78a-3a2f-4827-899f-980ac632cee9', $q$E-prescribing and lab/imaging order integration keep clinical data in one place$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0554d78a-3a2f-4827-899f-980ac632cee9', $q$Backed by Veradigm's broader healthcare technology and interoperability network$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0554d78a-3a2f-4827-899f-980ac632cee9', $q$Designed with small and independent practice workflows in mind$q$, 4);
