INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0554d78a-3a2f-4827-899f-980ac632cee9', $q$Ownership changes over the years have altered product direction and support structure$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0554d78a-3a2f-4827-899f-980ac632cee9', $q$Initial setup and template configuration can take meaningful time to get right$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('0554d78a-3a2f-4827-899f-980ac632cee9', $q$What is Practice Fusion used for?$q$, $q$Practice Fusion is a cloud-based EHR used by small and independent medical practices to chart patient visits, e-prescribe medications, order labs and imaging, and manage scheduling and basic billing workflows.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('0554d78a-3a2f-4827-899f-980ac632cee9', $q$Who owns Practice Fusion today?$q$, $q$Practice Fusion is part of Veradigm (formerly associated with Allscripts), which continues to operate it as a distinct EHR product for outpatient practices.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('0554d78a-3a2f-4827-899f-980ac632cee9', $q$How much does Practice Fusion cost?$q$, $q$Current pricing is not publicly published; practices typically need to contact Veradigm sales directly to get a quote based on practice size and needs.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('0554d78a-3a2f-4827-899f-980ac632cee9', $q$Is Practice Fusion suitable for large hospital systems?$q$, $q$Practice Fusion is primarily built for small to mid-sized outpatient practices, and larger hospital systems or multi-specialty networks generally require more enterprise-oriented EHR platforms.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('0554d78a-3a2f-4827-899f-980ac632cee9', $q$Does Practice Fusion support e-prescribing of controlled substances?$q$, $q$Yes, Practice Fusion supports electronic prescribing, including controlled substances, where the practice meets applicable state and DEA requirements.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0554d78a-3a2f-4827-899f-980ac632cee9', $q$Solo primary care practice going digital$q$, $q$A solo physician transitioning from paper charts uses Practice Fusion's browser-based charting and templates to document visits without investing in on-site servers.$q$, $q$Solo practitioners$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0554d78a-3a2f-4827-899f-980ac632cee9', $q$Small multi-provider clinic coordinating care$q$, $q$A small group practice uses shared scheduling, charting, and lab/imaging order integration to keep multiple providers aligned on patient care.$q$, $q$Small group practices$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0554d78a-3a2f-4827-899f-980ac632cee9', $q$Practice managing e-prescribing workflows$q$, $q$Front-office and clinical staff use e-prescribing tools to route prescriptions, including controlled substances, directly to pharmacies from the patient chart.$q$, $q$Clinical staff and physicians$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0554d78a-3a2f-4827-899f-980ac632cee9', $q$Practice tracking quality measures$q$, $q$A practice participating in value-based care programs uses built-in reporting to document and track quality measures required by payers.$q$, $q$Practice administrators$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('0554d78a-3a2f-4827-899f-980ac632cee9', $q$Standard$q$, $q$Contact for pricing$q$, $q$Custom$q$, $q$["Cloud-based EHR charting","E-prescribing","Scheduling","Lab and imaging order integration","Patient portal access"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('0554d78a-3a2f-4827-899f-980ac632cee9', $q$Enterprise / Multi-provider$q$, $q$Contact for pricing$q$, $q$Custom$q$, $q$["All Standard features","Multi-provider scheduling and charting","Billing and clearinghouse integration","Quality measure reporting","Dedicated onboarding support"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0554d78a-3a2f-4827-899f-980ac632cee9', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Practice Fusion is a cloud-based electronic health record (EHR) platform originally built to give small, independent medical practices an affordable way to move off paper charts. Launched in 2005 and headquartered in San Francisco, the company grew by offering browser-based charting that required no local server or IT department, a model that made it one of the more widely adopted ambulatory EHR systems among solo and small-group physicians in the United States.$q$, $q$The platform now operates under Veradigm (formerly part of Allscripts), which acquired Practice Fusion and folded it into a broader health-technology portfolio. Practice Fusion still functions as a distinct product, combining an EHR with e-prescribing, lab and imaging orders, patient charting, scheduling, and basic billing tools designed for outpatient primary care and specialty practices.$q$, $q$Because it runs entirely in a web browser, Practice Fusion appeals to practices that want to avoid on-premise hardware and IT overhead. It is positioned less as an enterprise health system solution and more as a practical, day-to-day charting and workflow tool for independent clinicians and small clinics managing patient care without a large administrative staff.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0554d78a-3a2f-4827-899f-980ac632cee9', $q$who-practice-fusion-is-for$q$, $q$Who Practice Fusion Is For$q$, 2, ARRAY[$q$Practice Fusion is aimed squarely at solo practitioners and small-to-mid-sized outpatient practices, particularly in primary care, family medicine, and common specialties that don't require highly specialized charting templates. Independent physicians who want an EHR they can start using quickly, without a lengthy IT deployment, are the core audience.$q$, $q$It also suits practices that are cost-conscious and want to consolidate charting, e-prescribing, and basic scheduling in a single browser-based system rather than stitching together multiple point solutions. Clinics transitioning off paper records for the first time often find the interface approachable since it mirrors familiar chart and note structures.$q$, $q$New and growing practices that expect to scale staff or patient volume over time may also appreciate that Practice Fusion is cloud-hosted, meaning updates and infrastructure are handled centrally rather than requiring in-house servers or upgrades managed by practice staff.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0554d78a-3a2f-4827-899f-980ac632cee9', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Large hospital systems, multi-specialty groups, or health networks with complex interoperability, billing, and reporting requirements will generally outgrow what Practice Fusion is designed to handle. Organizations needing deep integration with hospital ERP systems, advanced revenue-cycle management, or highly specialized clinical templates should look toward enterprise EHR platforms built for that scale.$q$, $q$Practices in specialties with heavy dependence on complex procedural documentation, such as surgical specialties or inpatient care, may find the charting tools too general-purpose for their workflows and prefer a specialty-specific EHR instead.$q$, $q$Practices that require transparent, self-service pricing without a sales conversation may also find the process frustrating, since current pricing for Practice Fusion is typically handled through direct contact rather than published rate cards, which can slow down evaluation for teams comparing several vendors quickly.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0554d78a-3a2f-4827-899f-980ac632cee9', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At its core, Practice Fusion provides cloud-based charting with customizable note templates, allowing clinicians to document visits using structured or free-text formats depending on specialty and personal preference. Charting is accessible from any internet-connected browser, which supports practices with multiple locations or providers working remote or hybrid schedules.$q$, $q$The platform includes electronic prescribing (e-prescribing), including support for controlled substances where applicable, along with lab and imaging order integration so results can flow back into the patient chart. Scheduling tools help front-office staff manage appointments, and patient charts consolidate history, medications, allergies, and visit notes in one place.$q$, $q$Additional functionality includes a patient portal for basic communication and record access, reporting tools to support quality measure tracking, and integrations with billing and clearinghouse partners for claims submission. As part of Veradigm, Practice Fusion also benefits from broader interoperability efforts tied to health information exchange standards.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0554d78a-3a2f-4827-899f-980ac632cee9', $q$the-practice-fusion-experience$q$, $q$The Practice Fusion Experience$q$, 2, ARRAY[$q$Day-to-day use of Practice Fusion centers on a browser-based dashboard where clinicians move between the schedule, patient charts, and messaging without needing separate installed software. For small practices, this generally translates into a shorter setup period compared to legacy, server-based EHR systems.$q$, $q$Clinicians who have used Practice Fusion for years often describe the charting workflow as straightforward once templates are configured, though like most EHR software, the initial setup and customization period requires an investment of time to tailor templates, favorites, and order sets to a specific practice's style.$q$, $q$Support and onboarding are handled through Veradigm's customer success channels, and because pricing and contract terms are typically discussed directly with a sales representative, practices evaluating the platform should expect a guided sales and onboarding process rather than instant self-serve signup.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0554d78a-3a2f-4827-899f-980ac632cee9', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
