INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('278217f3-1beb-4f01-8213-5430c71d5245', $q$Time & Billing$q$, $q$Built-in timers, billable and non-billable time tracking, and customizable invoice generation for hourly, flat-fee, or contingency matters.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('278217f3-1beb-4f01-8213-5430c71d5245', $q$Trust Accounting$q$, $q$IOLTA-compliant trust ledgers with three-way reconciliation to help firms keep client funds properly separated and audit-ready.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('278217f3-1beb-4f01-8213-5430c71d5245', $q$Matter Management$q$, $q$A central record for each case that links documents, contacts, notes, tasks, and billing entries together.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('278217f3-1beb-4f01-8213-5430c71d5245', $q$Client Intake & CRM$q$, $q$Lead capture forms and pipeline tracking to manage prospective clients before they become active matters.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('278217f3-1beb-4f01-8213-5430c71d5245', $q$Client Portal$q$, $q$A secure, branded portal where clients can view case updates, share documents, and message the firm directly.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('278217f3-1beb-4f01-8213-5430c71d5245', $q$Payment Processing$q$, $q$Integrated online payments allowing clients to pay invoices by credit card or ACH directly from an invoice link.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('278217f3-1beb-4f01-8213-5430c71d5245', $q$Document Management & Automation$q$, $q$Centralized document storage with templates for generating routine legal documents and filings faster.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('278217f3-1beb-4f01-8213-5430c71d5245', $q$Calendar & Task Management$q$, $q$Shared calendars, task assignment, and deadline tracking that sync with Outlook and Google Calendar.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('278217f3-1beb-4f01-8213-5430c71d5245', $q$Reporting & Analytics$q$, $q$Dashboards covering billable hours, outstanding invoices, and staff productivity to support firm-level decision making.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('278217f3-1beb-4f01-8213-5430c71d5245', $q$Third-Party Integrations$q$, $q$Connections to QuickBooks, Outlook, Gmail, Dropbox, and Zapier to fit into a firm's existing software stack.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('278217f3-1beb-4f01-8213-5430c71d5245', $q$Clean, easy-to-learn interface compared to many legacy legal practice management tools$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('278217f3-1beb-4f01-8213-5430c71d5245', $q$Built-in trust accounting with three-way reconciliation supports IOLTA compliance$q$, 1);
