INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('278217f3-1beb-4f01-8213-5430c71d5245', $q$Native mobile apps let attorneys track time and check matters away from the desk$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('278217f3-1beb-4f01-8213-5430c71d5245', $q$Integrated payment processing simplifies client invoicing and collections$q$, 4);
