INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bc3b8540-7633-45e3-8bb9-3540341f319d', $q$Project Management$q$, $q$Centralizes drawings, specifications, RFIs, submittals, meeting minutes, and daily logs in one shared project record.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bc3b8540-7633-45e3-8bb9-3540341f319d', $q$Financial Management$q$, $q$Tracks budgets, commitments, change orders, invoicing, and forecasting tied directly to field activity.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bc3b8540-7633-45e3-8bb9-3540341f319d', $q$Quality & Safety$q$, $q$Supports inspections, observations, and incident tracking to help teams manage jobsite risk and compliance.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bc3b8540-7633-45e3-8bb9-3540341f319d', $q$Scheduling$q$, $q$Builds and shares project timelines alongside the documentation and tasks that support them.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bc3b8540-7633-45e3-8bb9-3540341f319d', $q$Workforce Management$q$, $q$Manages field crew timecards, certifications, and productivity tracking from a single system.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bc3b8540-7633-45e3-8bb9-3540341f319d', $q$Mobile App$q$, $q$Extends drawings, daily logs, RFIs, and inspections to phones and tablets for jobsite use.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bc3b8540-7633-45e3-8bb9-3540341f319d', $q$Document Control$q$, $q$Keeps drawing and specification revisions organized so field teams always reference the current version.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bc3b8540-7633-45e3-8bb9-3540341f319d', $q$Integrations & API$q$, $q$Connects to accounting, estimating, BIM, and other construction software through an open platform and marketplace.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bc3b8540-7633-45e3-8bb9-3540341f319d', $q$Reporting & Analytics$q$, $q$Provides dashboards and reports that surface cost, schedule, and risk data across projects.$q$, 8);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bc3b8540-7633-45e3-8bb9-3540341f319d', $q$Connects field and office teams around a single, real-time source of project data$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bc3b8540-7633-45e3-8bb9-3540341f319d', $q$Broad module coverage spans project management, financials, quality, safety, and workforce tracking$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bc3b8540-7633-45e3-8bb9-3540341f319d', $q$Strong mobile app supports documentation directly from the jobsite$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bc3b8540-7633-45e3-8bb9-3540341f319d', $q$Open API and marketplace allow integration with existing accounting and estimating tools$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bc3b8540-7633-45e3-8bb9-3540341f319d', $q$Extensive training resources and certification courses support long-term adoption$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bc3b8540-7633-45e3-8bb9-3540341f319d', $q$Pricing is not published and requires a sales conversation based on construction volume$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bc3b8540-7633-45e3-8bb9-3540341f319d', $q$Initial setup and configuration can take significant time and internal resources$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bc3b8540-7633-45e3-8bb9-3540341f319d', $q$Learning curve for field staff unfamiliar with digital project management tools$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bc3b8540-7633-45e3-8bb9-3540341f319d', $q$Can be more platform than very small contractors or single-project builders need$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bc3b8540-7633-45e3-8bb9-3540341f319d', $q$Full value depends on consistent, organization-wide adoption rather than partial use$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('bc3b8540-7633-45e3-8bb9-3540341f319d', $q$What is Procore used for?$q$, $q$Procore is used to manage construction projects end to end, connecting drawings, RFIs, submittals, budgets, schedules, safety inspections, and daily field logs in one cloud-based system.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('bc3b8540-7633-45e3-8bb9-3540341f319d', $q$How much does Procore cost?$q$, $q$Procore does not publish standard pricing. Costs are typically quoted individually based on a company's annual construction volume and the modules selected, so interested firms need to contact Procore for a quote.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('bc3b8540-7633-45e3-8bb9-3540341f319d', $q$Does Procore offer a free trial?$q$, $q$Procore periodically offers demos and trial access through its sales team, but there is no self-serve free trial or free plan; access is arranged through a sales conversation.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('bc3b8540-7633-45e3-8bb9-3540341f319d', $q$Is Procore only for general contractors?$q$, $q$No. While general contractors are common users, Procore is also used by owners, specialty and trade subcontractors, construction managers, and architects who need visibility into a project.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('bc3b8540-7633-45e3-8bb9-3540341f319d', $q$Does Procore have a mobile app?$q$, $q$Yes. Procore offers a mobile app for iOS and Android that lets field teams access drawings, daily logs, RFIs, punch lists, and inspections directly from the jobsite.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bc3b8540-7633-45e3-8bb9-3540341f319d', $q$Multi-project portfolio oversight$q$, $q$General contractors running several concurrent jobs use Procore to track budgets, schedules, and risk across an entire portfolio from one dashboard.$q$, $q$General contractors and construction managers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bc3b8540-7633-45e3-8bb9-3540341f319d', $q$Owner visibility across contractors$q$, $q$Owners and developers use Procore to maintain a consistent view of cost and progress across multiple contractors and project sites.$q$, $q$Owners and developers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bc3b8540-7633-45e3-8bb9-3540341f319d', $q$Subcontractor document coordination$q$, $q$Specialty trade contractors use Procore to manage submittals, drawing revisions, and daily documentation on jobsites run by a general contractor.$q$, $q$Specialty and trade contractors$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bc3b8540-7633-45e3-8bb9-3540341f319d', $q$Jobsite safety and quality tracking$q$, $q$Field teams use Procore's inspection and observation tools to document safety walks, quality checks, and incident reports as work progresses.$q$, $q$Field superintendents and safety managers$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('bc3b8540-7633-45e3-8bb9-3540341f319d', $q$Standard$q$, $q$Contact for pricing$q$, $q$Annual, based on construction volume$q$, $q$["Core project management tools","Document and drawing management","Basic reporting","Mobile app access"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('bc3b8540-7633-45e3-8bb9-3540341f319d', $q$Advanced$q$, $q$Contact for pricing$q$, $q$Annual, based on construction volume$q$, $q$["Full financial management suite","Quality and safety modules","Workforce management","Expanded integrations and API access"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bc3b8540-7633-45e3-8bb9-3540341f319d', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Procore is a cloud-based construction management platform built to connect every phase of a project, from preconstruction and design through closeout, inside a single system of record. Rather than forcing teams to juggle spreadsheets, email threads, and disconnected point solutions, Procore centralizes drawings, budgets, RFIs, submittals, schedules, and daily logs so that owners, general contractors, specialty contractors, and architects can work from the same live data set.$q$, $q$The platform is organized around a central hub of tools spanning project management, financial management, quality and safety, and workforce management, all accessible from a web browser or the Procore mobile app. Because updates sync in real time, a change made by a superintendent in the field is immediately visible to the project executive in the office, reducing the lag and miscommunication that traditionally plague construction projects.$q$, $q$Procore has grown from a niche software vendor into one of the most widely recognized names in construction technology, serving general contractors, owners, and specialty trades across commercial, residential, industrial, and public infrastructure work. Its open API and marketplace of integrations allow it to sit at the center of a broader technology stack rather than replacing every existing tool a construction firm already relies on. The company has also expanded well beyond its original document and drawing management roots into financial controls, workforce tracking, and preconstruction estimating, positioning itself as a full project lifecycle platform rather than a single-purpose tool, so firms can consolidate several point solutions into one vendor relationship over time.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bc3b8540-7633-45e3-8bb9-3540341f319d', $q$who-procore-is-for$q$, $q$Who Procore Is For$q$, 2, ARRAY[$q$Procore is best suited to general contractors, construction managers, and owners who run multiple concurrent projects and need visibility into cost, schedule, and risk across an entire portfolio. Mid-size to large firms with dedicated project management and accounting staff tend to see the clearest return, since the platform's breadth is designed to replace many disconnected tools with one connected system.$q$, $q$It also fits specialty and trade contractors who work as subcontractors on Procore-run jobsites and need a reliable way to manage submittals, drawings, and daily documentation without maintaining separate internal systems. Owners and developers who want a single source of truth across many contractors and projects, particularly in commercial, healthcare, education, and public works construction, are a strong match as well.$q$, $q$Firms that already have, or are ready to build, some internal process discipline around documentation, RFIs, and scheduling tend to get the most value, since Procore is a system that reflects and reinforces good project controls rather than inventing them from scratch.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bc3b8540-7633-45e3-8bb9-3540341f319d', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Very small contractors, solo builders, or handyman-style operations running one or two simple projects a year may find Procore more platform than they need. The breadth of modules and the effort required for setup, field training, and change management can outweigh the benefit for a business that could get by on a lightweight scheduling and invoicing tool.$q$, $q$Companies unwilling to invest in onboarding and ongoing administration should also think twice. Procore's real value comes from consistent use across the field and office, and organizations that plan to activate only a sliver of the platform without dedicating someone to configuration and adoption often struggle to justify the cost.$q$, $q$Because Procore typically prices around annual construction volume and requires a sales conversation rather than a self-serve signup, budget-constrained teams that want transparent, low-commitment monthly pricing, or teams that need an instant answer on cost, may prefer a simpler, publicly priced alternative instead. Firms with highly informal processes and no appetite for standardizing how RFIs, submittals, or daily logs get recorded may also find the platform's structure feels heavier than the value it delivers in the short term.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bc3b8540-7633-45e3-8bb9-3540341f319d', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$Procore's project management tools cover drawings and specifications, RFIs, submittals, meeting minutes, punch lists, and daily logs, giving field and office teams a shared, timestamped record of everything happening on a job. Scheduling tools let teams build, share, and track project timelines directly alongside the documentation that supports them.$q$, $q$On the financial side, Procore offers budgeting, commitments, change orders, invoicing, and forecasting tools designed to keep project cost data tied directly to field activity, along with integrations to accounting systems many construction firms already use. Quality and safety modules support inspections, observations, and incident tracking to help teams manage risk and compliance across a jobsite.$q$, $q$Workforce management features cover timecards, certifications, and productivity tracking for field crews, while an open platform and app marketplace let firms connect Procore to estimating, accounting, BIM, and other specialized tools. The Procore mobile app extends most of this functionality to phones and tablets so field teams can log information from the jobsite itself, capture photos against specific locations on a drawing, and route issues to the right person without waiting to return to the office.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bc3b8540-7633-45e3-8bb9-3540341f319d', $q$the-procore-experience$q$, $q$The Procore Experience$q$, 2, ARRAY[$q$New customers typically go through a guided onboarding process with a Procore implementation team, since the platform's depth means configuration choices around project templates, permissions, and workflows matter for long-term adoption. Procore also offers extensive self-serve training resources, certification courses, and a large user community that help both administrators and field staff get comfortable with the system.$q$, $q$Day to day, the interface is organized by project, with a left-hand navigation exposing whichever tools an administrator has enabled for that job. Field users generally interact most with drawings, daily logs, and RFIs from the mobile app, while office staff spend more time in the financial and reporting tools from a desktop browser.$q$, $q$Because so much of a project's documentation lives in one place, teams that commit to using Procore consistently often describe the experience as reducing the back-and-forth of tracking down the latest drawing revision or approval status. The tradeoff is a genuine learning curve during rollout, and firms that skip structured training sometimes only scratch the surface of what the platform can do, leaving valuable modules underused while staff continue to lean on older, informal habits alongside the new system.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('bc3b8540-7633-45e3-8bb9-3540341f319d', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('bc3b8540-7633-45e3-8bb9-3540341f319d', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
