INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('bc3b8540-7633-45e3-8bb9-3540341f319d', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2160b497-eee0-445d-8e03-8e017410723b', $q$Task Management$q$, $q$Create tasks and subtasks, assign owners, set priorities and due dates, and organize work into lists within each project.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2160b497-eee0-445d-8e03-8e017410723b', $q$Multiple Project Views$q$, $q$Switch between table view, Kanban boards, and Gantt-style timelines to track the same work in whichever format suits the team.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2160b497-eee0-445d-8e03-8e017410723b', $q$Time Tracking$q$, $q$Log time manually or with built-in timers against tasks, then compare estimated versus actual time spent on projects.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2160b497-eee0-445d-8e03-8e017410723b', $q$Proofing & File Review$q$, $q$Upload images, PDFs, and other files for markup, time-stamped comments, and approval workflows without leaving the platform.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2160b497-eee0-445d-8e03-8e017410723b', $q$Discussions & Chat$q$, $q$Hold threaded project discussions and real-time group chat so conversations stay attached to the relevant work.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2160b497-eee0-445d-8e03-8e017410723b', $q$Custom Workflows & Roles$q$, $q$Define custom task statuses and workflows, and set granular roles and permissions for team members and client guests.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2160b497-eee0-445d-8e03-8e017410723b', $q$Reports & Dashboards$q$, $q$View progress, workload, and time-tracking reports across projects to spot bottlenecks and monitor team capacity.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2160b497-eee0-445d-8e03-8e017410723b', $q$Notes & File Storage$q$, $q$Store project files and create shared notes and documents alongside tasks, keeping related information in one place.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2160b497-eee0-445d-8e03-8e017410723b', $q$Calendar & Announcements$q$, $q$See deadlines and milestones on a shared calendar and post company-wide or project-wide announcements to keep teams aligned.$q$, 8);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2160b497-eee0-445d-8e03-8e017410723b', $q$Flat monthly pricing covers unlimited users, so costs don't rise as the team grows$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2160b497-eee0-445d-8e03-8e017410723b', $q$Combines task management, time tracking, proofing, chat, and file storage in one tool$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2160b497-eee0-445d-8e03-8e017410723b', $q$Relatively gentle learning curve compared to more complex, feature-dense competitors$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2160b497-eee0-445d-8e03-8e017410723b', $q$Built-in proofing and approval tools are useful for agencies and creative teams$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2160b497-eee0-445d-8e03-8e017410723b', $q$Custom roles and permissions make it easy to include clients or contractors as guests$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2160b497-eee0-445d-8e03-8e017410723b', $q$Fewer native integrations and a smaller API ecosystem than larger competitors$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2160b497-eee0-445d-8e03-8e017410723b', $q$Less configurable than highly customizable tools like ClickUp or Monday.com$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2160b497-eee0-445d-8e03-8e017410723b', $q$Flat fee can feel less economical for very small teams or solo users$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2160b497-eee0-445d-8e03-8e017410723b', $q$Advanced automation and workflow customization options are more limited$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2160b497-eee0-445d-8e03-8e017410723b', $q$Reporting, while useful, is less granular than dedicated analytics-focused platforms$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('2160b497-eee0-445d-8e03-8e017410723b', $q$Does ProofHub charge per user?$q$, $q$No. ProofHub uses flat-rate pricing, so the monthly fee covers unlimited users on the account rather than charging per seat.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('2160b497-eee0-445d-8e03-8e017410723b', $q$Is there a free trial for ProofHub?$q$, $q$Yes, ProofHub offers a free trial that lets teams test the platform's task management, time tracking, and proofing features before committing to a paid plan.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('2160b497-eee0-445d-8e03-8e017410723b', $q$Does ProofHub have mobile apps?$q$, $q$Yes, ProofHub provides mobile apps for iOS and Android so team members can update tasks, track time, and comment while away from a desktop.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('2160b497-eee0-445d-8e03-8e017410723b', $q$Can clients or external collaborators use ProofHub?$q$, $q$Yes, ProofHub supports custom roles and permissions that allow admins to invite clients or contractors as guests with limited access to specific projects.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('2160b497-eee0-445d-8e03-8e017410723b', $q$Does ProofHub include time tracking and reporting?$q$, $q$Yes, ProofHub includes built-in time tracking with timers and manual entry, plus reporting dashboards that summarize progress, workload, and time spent across projects.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2160b497-eee0-445d-8e03-8e017410723b', $q$Managing agency client projects$q$, $q$Agencies run multiple client projects in separate workspaces, using custom roles to give clients limited guest access for reviewing deliverables and leaving proofing feedback.$q$, $q$Marketing and creative agencies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2160b497-eee0-445d-8e03-8e017410723b', $q$Coordinating distributed teams$q$, $q$Remote and hybrid teams use task boards, discussions, and mobile apps to stay aligned on deadlines without needing separate chat and file-sharing tools.$q$, $q$Remote and hybrid teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2160b497-eee0-445d-8e03-8e017410723b', $q$Tracking billable time across projects$q$, $q$Consultancies log time against tasks and projects using built-in timers, then pull reports to compare estimated versus actual hours for client billing.$q$, $q$Consultancies and professional services firms$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2160b497-eee0-445d-8e03-8e017410723b', $q$Reviewing and approving creative assets$q$, $q$Design and marketing teams upload images, PDFs, and videos for stakeholder markup and time-stamped approval, cutting down on email-based feedback loops.$q$, $q$Design and marketing teams$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('2160b497-eee0-445d-8e03-8e017410723b', $q$Essential$q$, $q$$45/month$q$, $q$billed annually (flat rate for unlimited users)$q$, $q$["Unlimited users","Task management and boards","Time tracking","File storage","Discussions and chat"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('2160b497-eee0-445d-8e03-8e017410723b', $q$Ultimate Control$q$, $q$$89/month$q$, $q$billed annually (flat rate for unlimited users)$q$, $q$["Everything in Essential","Custom roles and workflows","Advanced reporting","White labeling","Proofing and approval tools"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2160b497-eee0-445d-8e03-8e017410723b', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$ProofHub is a project management and team collaboration platform built to replace a scattered stack of task trackers, chat apps, file-sharing tools, and time trackers with a single workspace. Teams plan work, assign tasks, track time, share files, discuss projects, and review deliverables all from one login, which is the central pitch: fewer tools, fewer subscriptions, less context-switching between apps that don't talk to each other.$q$, $q$What sets ProofHub apart from most competitors in the space is its pricing structure. Rather than charging per user per month, which is the norm for tools like Asana, Monday.com, or ClickUp, ProofHub charges a single flat monthly fee that covers unlimited users on the account. This makes cost predictable as a team grows, since adding new members or contractors to a project never changes the bill.$q$, $q$The platform organizes work around projects, each of which can contain task lists, Kanban boards, Gantt-style timelines, discussions, files, and notes. Custom workflows and roles let admins control who can see and do what, which appeals to agencies and consultancies managing multiple clients or teams with different access needs inside the same account.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2160b497-eee0-445d-8e03-8e017410723b', $q$who-proofhub-is-for$q$, $q$Who ProofHub Is For$q$, 2, ARRAY[$q$ProofHub is a strong fit for small and mid-sized businesses, agencies, and consultancies whose headcount fluctuates or is large enough that per-seat pricing from competitors becomes expensive. Because the flat-rate model covers unlimited users, teams that regularly bring on freelancers, contractors, or client stakeholders as guests benefit from being able to add people without recalculating monthly costs.$q$, $q$Marketing agencies and creative teams are a particularly good match, since ProofHub's built-in proofing and review tools let clients and internal reviewers leave time-stamped comments and markup directly on images, PDFs, and other files, reducing the need for separate approval or file-review software layered on top of the project tool.$q$, $q$Operations-minded managers who want one dashboard for task tracking, time logging, and reporting across several concurrent projects also do well here, as do organizations that want a single tool simple enough for non-technical staff to adopt without extensive training, since ProofHub deliberately keeps its interface less cluttered than some of the more feature-dense competitors.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2160b497-eee0-445d-8e03-8e017410723b', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Very small teams or solo freelancers who only need to track a handful of personal tasks may find ProofHub's flat monthly fee harder to justify than a free or low-cost per-user plan from a lighter competitor, since the pricing advantage only really pays off once a team is large enough that per-seat costs would otherwise add up.$q$, $q$Organizations that depend heavily on deep integrations with a specific ecosystem, such as advanced Salesforce workflows, complex DevOps toolchains, or extensive custom API automation, may find ProofHub's integration library and API surface more limited than what dedicated engineering-focused platforms like Jira or Linear offer.$q$, $q$Teams that want highly granular, endlessly customizable views, formulas, and automation rules, the kind found in tools like ClickUp or Monday.com, may find ProofHub's feature set comparatively straightforward, since its design philosophy favors simplicity and ease of adoption over maximum configurability.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2160b497-eee0-445d-8e03-8e017410723b', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At its core, ProofHub offers multiple ways to visualize the same work: task lists, Kanban-style boards, table views, and Gantt-style timelines called Gantt charts, so different teams or individuals can track progress in the layout that suits them without needing separate software for each view.$q$, $q$Beyond scheduling, ProofHub bundles time tracking with timers and manual entry, built-in proofing tools for markup and approval on creative files, group chat and project discussions, custom project workflows and roles, notes and file storage, and reporting dashboards that summarize workload, time spent, and project progress across the account.$q$, $q$Custom roles and permissions let admins control exactly what each team member or client can view and edit, while announcements and calendars help keep distributed teams aligned on deadlines and company-wide updates without needing a separate internal communications tool.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2160b497-eee0-445d-8e03-8e017410723b', $q$the-proofhub-experience$q$, $q$The ProofHub Experience$q$, 2, ARRAY[$q$Day to day, using ProofHub feels closer to using a focused internal hub than a sprawling enterprise suite. The interface groups projects on a left-hand sidebar, and switching between task boards, discussions, and files within a project is designed to happen without page reloads or jarring context switches, which keeps the experience feeling responsive even with several active projects open.$q$, $q$New users generally find the learning curve gentler than heavyweight competitors, since ProofHub intentionally limits the number of nested settings and configuration screens; most teams can set up their first project, invite collaborators, and start assigning tasks within an afternoon rather than needing a lengthy onboarding process.$q$, $q$The mobile apps extend core functionality, task updates, comments, and time tracking, to iOS and Android, so field teams and remote collaborators aren't tied to a desktop browser, and the overall experience is consistent with the flat-rate promise: a single, moderately opinionated workspace rather than a highly customizable but more complex alternative.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('2160b497-eee0-445d-8e03-8e017410723b', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
