INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('2160b497-eee0-445d-8e03-8e017410723b', 'ee5576d4-5994-49f9-84c2-c9a84cc884f6') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('37206632-9f9a-460f-8492-df6a397cf34f', $q$Real Estate CRM & Contact Management$q$, $q$Tracks agents, clients, properties, and their relationships across the full transaction lifecycle within a Salesforce-based data model.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('37206632-9f9a-460f-8492-df6a397cf34f', $q$Lead Capture & Routing$q$, $q$Pulls in leads from websites, portals, and referral sources and automatically routes them to the right agent or team based on configurable rules.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('37206632-9f9a-460f-8492-df6a397cf34f', $q$Marketing Automation$q$, $q$Builds email drip campaigns, segments audiences, and tracks engagement so lead nurturing stays consistent across the whole brokerage.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('37206632-9f9a-460f-8492-df6a397cf34f', $q$Transaction Management$q$, $q$Tracks deals from initial contract through closing, keeping documents, milestones, and stakeholders organized in one record.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('37206632-9f9a-460f-8492-df6a397cf34f', $q$Listing Management$q$, $q$Centralizes property listing data and syncs it across marketing channels, agent sites, and internal pipelines.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('37206632-9f9a-460f-8492-df6a397cf34f', $q$Back Office & Commission Accounting$q$, $q$Handles commission calculations, disbursements, and compliance reporting for broker-owners managing agent payouts.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('37206632-9f9a-460f-8492-df6a397cf34f', $q$Reporting & Analytics Dashboards$q$, $q$Gives managers visibility into pipeline health, agent productivity, and marketing performance through configurable dashboards.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('37206632-9f9a-460f-8492-df6a397cf34f', $q$Mobile Apps (iOS & Android)$q$, $q$Lets agents access contacts, leads, and transaction updates from native mobile apps while working in the field.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('37206632-9f9a-460f-8492-df6a397cf34f', $q$Salesforce AppExchange Integrations & API$q$, $q$Connects Propertybase to e-signature tools, financial systems, and other software through Salesforce's ecosystem and an open API.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('37206632-9f9a-460f-8492-df6a397cf34f', $q$Workflow Automation$q$, $q$Automates lead assignment, follow-up reminders, and transaction task sequencing to reduce manual administrative work.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('37206632-9f9a-460f-8492-df6a397cf34f', $q$Built on Salesforce, giving it a highly customizable and scalable foundation as an organization grows$q$, 0);
