INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('37206632-9f9a-460f-8492-df6a397cf34f', $q$Access to the wider Salesforce AppExchange ecosystem and an open API for deep integrations$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('37206632-9f9a-460f-8492-df6a397cf34f', $q$Native mobile apps let agents manage leads and transactions from the field$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('37206632-9f9a-460f-8492-df6a397cf34f', $q$Pricing is not fully transparent and typically requires a sales conversation to scope$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('37206632-9f9a-460f-8492-df6a397cf34f', $q$Steep learning curve due to the underlying Salesforce complexity$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('37206632-9f9a-460f-8492-df6a397cf34f', $q$Implementation and onboarding can be lengthy and may require dedicated administrator or consultant support$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('37206632-9f9a-460f-8492-df6a397cf34f', $q$Likely overkill and cost-prohibitive for solo agents or very small teams$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('37206632-9f9a-460f-8492-df6a397cf34f', $q$Deep customization generally requires Salesforce admin or developer expertise$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('37206632-9f9a-460f-8492-df6a397cf34f', $q$Is Propertybase built on Salesforce?$q$, $q$Yes. Propertybase Salesforce Edition is built natively on the Salesforce platform, which is why it can offer deep customization, automation, and integration capabilities beyond a typical standalone CRM.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('37206632-9f9a-460f-8492-df6a397cf34f', $q$How much does Propertybase cost?$q$, $q$Propertybase does not publish full pricing. Third-party sources have cited a starting rate of roughly $79 per user per month for Salesforce Edition with a 10-user minimum, but final pricing depends on edition, user count, and add-ons, and requires a custom quote.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('37206632-9f9a-460f-8492-df6a397cf34f', $q$Who owns Propertybase?$q$, $q$Propertybase is owned by Lone Wolf Technologies, which acquired the platform in August 2021 to combine its CRM, website, and lead-generation tools with Lone Wolf's transaction and back-office software.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('37206632-9f9a-460f-8492-df6a397cf34f', $q$Does Propertybase have a mobile app?$q$, $q$Yes, Propertybase offers native mobile apps for iOS and Android so agents can manage leads, contacts, and transactions while working outside the office.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('37206632-9f9a-460f-8492-df6a397cf34f', $q$Is Propertybase a good fit for a solo agent or small team?$q$, $q$Generally no. Propertybase is built for brokerages and larger teams that need a scalable, configurable system; solo agents and very small teams are usually better served by lighter, less expensive CRMs.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('37206632-9f9a-460f-8492-df6a397cf34f', $q$Enterprise brokerage lead-to-close management$q$, $q$A multi-office residential brokerage uses Propertybase to capture leads from its website and portals, route them to agents, nurture them through automated marketing, and track every deal through to closing in one system.$q$, $q$Large residential brokerages with multiple offices and agent teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('37206632-9f9a-460f-8492-df6a397cf34f', $q$Commercial real estate deal and relationship management$q$, $q$A commercial real estate firm tracks complex, multi-stakeholder deals, longer sales cycles, and detailed property and tenant data using Propertybase's Salesforce-based data model.$q$, $q$Commercial real estate brokerages and investment sales teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('37206632-9f9a-460f-8492-df6a397cf34f', $q$Luxury and global real estate marketing$q$, $q$A luxury or internationally-focused brokerage uses Propertybase's marketing automation and listing tools to run coordinated campaigns across markets and languages for high-value properties.$q$, $q$Luxury residential and global real estate brokerages$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('37206632-9f9a-460f-8492-df6a397cf34f', $q$Back-office commission and accounting automation$q$, $q$A broker-owner uses the Propertybase back-office module to calculate commission splits, manage disbursements, and generate compliance reports across a large agent roster.$q$, $q$Broker-owners and real estate finance/operations teams$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('37206632-9f9a-460f-8492-df6a397cf34f', $q$Propertybase GO$q$, $q$Contact for pricing$q$, $q$Custom quote$q$, $q$["Streamlined CRM for brokerages and teams","Lead capture and follow-up tools","Email marketing campaigns","Mobile app access"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('37206632-9f9a-460f-8492-df6a397cf34f', $q$Propertybase Salesforce Edition$q$, $q$From approximately $79/user/month (10-user minimum, per third-party sources)$q$, $q$Per user, per month, with a custom quote for final pricing$q$, $q$["Full Salesforce-native CRM and data model","Advanced customization and workflow automation","Salesforce AppExchange integrations and API access","Enterprise-grade reporting and analytics"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('37206632-9f9a-460f-8492-df6a397cf34f', $q$Propertybase Back Office$q$, $q$Contact for pricing$q$, $q$Custom quote$q$, $q$["Commission calculation and disbursement","Accounting and financial reporting","Compliance and transaction documentation tracking","Integration with front-end CRM and transaction data"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('37206632-9f9a-460f-8492-df6a397cf34f', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Propertybase is a real estate CRM and transaction management platform built natively on the Salesforce platform, designed to help brokerages, agents, and real estate teams manage the entire client lifecycle in one system. Rather than functioning as a standalone tool, it layers real estate-specific data models, workflows, and marketing capabilities on top of Salesforce's enterprise-grade infrastructure, giving organizations a CRM that can scale from a regional brokerage to a multinational real estate group.$q$, $q$Founded in 2010, Propertybase grew into a family of real estate technology products built around its core Salesforce-based CRM, including the lead-generation tool BoldLeads, the streamlined Propertybase GO offering for smaller teams, and the deeper Propertybase Salesforce Edition aimed at enterprise brokerages. In August 2021, the company was acquired by Lone Wolf Technologies, a major provider of real estate transaction and back-office software, which now develops and markets Propertybase as part of a broader end-to-end platform spanning websites, lead generation, CRM, and back-office operations for agents and brokers.$q$, $q$At its core, Propertybase aims to unify the real estate business process, from capturing and nurturing leads, through marketing campaigns and listing management, to closing transactions and reconciling commissions, inside a single connected record system. Because it inherits Salesforce's automation, reporting, and integration capabilities, it functions less like a simple contact manager and more like an operating system for real estate organizations that want centralized data, configurable workflows, and long-term extensibility as their business grows.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('37206632-9f9a-460f-8492-df6a397cf34f', $q$who-propertybase-is-for$q$, $q$Who Propertybase Is For$q$, 2, ARRAY[$q$Propertybase is best suited to established residential brokerages and real estate teams that have outgrown lightweight, single-purpose CRMs and need a system that manages leads, marketing, and transactions together at scale. Brokerages with multiple offices, dozens or hundreds of agents, and a need for consistent, centralized reporting tend to get the most value from the platform's Salesforce-based architecture.$q$, $q$Commercial real estate firms and luxury or internationally-focused residential brokerages are also strong fits, since Propertybase's data model and marketing tools were built with complex deal structures, longer sales cycles, and cross-border listings in mind. Firms that need to track multiple stakeholders per deal, coordinate multi-market marketing campaigns, or manage sophisticated commission splits often find the platform's depth valuable in ways simpler consumer-grade CRMs are not designed to handle.$q$, $q$Organizations that already use Salesforce elsewhere in their business, or that have in-house administrators comfortable configuring a CRM platform, are particularly well positioned to adopt Propertybase successfully. Because the product is built on top of Salesforce rather than as an isolated application, teams with the internal capacity to customize objects, automations, and integrations can unlock significantly more value than organizations expecting a purely out-of-the-box experience.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('37206632-9f9a-460f-8492-df6a397cf34f', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Solo agents, independent contractors, and very small teams that need a simple, inexpensive way to track contacts and follow-ups are generally not the intended audience for Propertybase. The platform's scope and underlying Salesforce foundation introduce a level of complexity and cost that is difficult to justify for a single user managing a modest pipeline of clients.$q$, $q$Budget-conscious brokerages that want fully transparent, self-serve pricing may also find Propertybase frustrating, since exact costs are not published in detail and typically require a sales conversation to scope based on user count, edition, and add-on modules. Teams that need to compare pricing quickly across several vendors before committing may prefer platforms with simpler, published plans.$q$, $q$Finally, organizations looking for a lightweight, plug-and-play CRM they can configure themselves in an afternoon should look elsewhere. Propertybase's flexibility comes from its Salesforce foundation, which generally benefits from dedicated implementation support or an experienced administrator; teams without that capacity, or without patience for a longer onboarding process, may find the learning curve steeper than expected.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('37206632-9f9a-460f-8492-df6a397cf34f', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At the center of Propertybase is a real estate-specific CRM that tracks contacts, properties, and relationships across the full client journey, paired with lead capture and routing tools that funnel inquiries from websites, portals, and referral sources directly into agent pipelines. Built-in marketing automation lets teams build drip campaigns, segment audiences, and monitor engagement, so lead nurturing and follow-up happen consistently across a brokerage rather than depending on individual agents' habits.$q$, $q$Beyond the front end, Propertybase provides transaction and listing management tools that track deals from contract to close, alongside a back-office module for commission calculations, accounting, and compliance reporting, which is particularly relevant for broker-owners managing agent payouts. Reporting and analytics dashboards give managers visibility into pipeline health, agent performance, and marketing return, while native mobile apps for iOS and Android let agents update records and respond to leads while working in the field.$q$, $q$Because the platform sits on Salesforce, it also benefits from the wider Salesforce AppExchange ecosystem and an open API, allowing organizations to connect Propertybase to marketing tools, e-signature platforms, financial systems, and other software already in use. Workflow automation and task management features round out the platform, letting administrators define rules that assign leads, trigger follow-ups, and keep transactions moving without manual intervention at every step.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('37206632-9f9a-460f-8492-df6a397cf34f', $q$the-propertybase-experience$q$, $q$The Propertybase Experience$q$, 2, ARRAY[$q$Getting started with Propertybase is a more involved process than adopting a typical off-the-shelf CRM, since the platform is generally configured to match an organization's specific teams, territories, and transaction workflows. Most brokerages work through an onboarding or implementation phase, often with guidance from Propertybase or partner consultants, to map existing processes into the Salesforce-based data model before rolling the system out to agents.$q$, $q$Once configured, day-to-day use centers on dashboards, pipelines, and automated workflows that surface the right information to the right role, whether that is an agent following up on a new lead, a transaction coordinator tracking a closing, or a broker-owner reviewing commission reports. Users familiar with Salesforce's interface conventions will find some of that experience carries over, while newcomers typically need a period of training to get comfortable navigating the platform's depth.$q$, $q$Overall, the experience rewards organizations willing to invest in setup and ongoing administration with a highly capable, extensible system that can grow alongside the business, rather than a lightweight tool meant to be used immediately with no configuration. Support and account management come through Propertybase's parent company, Lone Wolf Technologies, and larger customers in particular tend to value the platform's ability to consolidate CRM, marketing, transactions, and back-office functions under one connected data model instead of juggling multiple disconnected products.$q$]::text[], 4);
