INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('95f3299d-181e-4436-824f-a995c9317a92', $q$What is Proposify used for?$q$, $q$Proposify is used to create, send, track, and electronically sign business proposals, helping sales teams standardize their proposal process and see how prospects engage with each document.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('95f3299d-181e-4436-824f-a995c9317a92', $q$Does Proposify offer a free trial?$q$, $q$Yes, Proposify offers a free trial period so teams can test the editor, templates, and tracking features before subscribing to a paid plan.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('95f3299d-181e-4436-824f-a995c9317a92', $q$Does Proposify include e-signatures?$q$, $q$Yes, legally binding electronic signatures are built into the platform, allowing recipients to approve and sign proposals directly within the document.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('95f3299d-181e-4436-824f-a995c9317a92', $q$Can Proposify integrate with a CRM?$q$, $q$Proposify integrates with a number of popular CRM platforms so proposal activity and deal status can be tracked alongside the rest of a team's sales data.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('95f3299d-181e-4436-824f-a995c9317a92', $q$Is Proposify suitable for small businesses or freelancers?$q$, $q$It can work for small teams, but the per-user pricing model tends to deliver the best value for businesses sending a steady volume of proposals rather than occasional one-off documents.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('95f3299d-181e-4436-824f-a995c9317a92', $q$Agency client proposals$q$, $q$Marketing, design, and consulting agencies use Proposify to send branded proposals with scopes of work and pricing options tailored to each client.$q$, $q$Agencies and consultancies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('95f3299d-181e-4436-824f-a995c9317a92', $q$B2B sales quoting$q$, $q$Sales teams use interactive pricing tables and templates to quickly turn a qualified lead into a professional, trackable quote.$q$, $q$B2B sales teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('95f3299d-181e-4436-824f-a995c9317a92', $q$Deal visibility for sales managers$q$, $q$Managers use approval workflows and analytics to monitor proposal activity, enforce pricing standards, and see where deals stall.$q$, $q$Sales leaders and managers$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('95f3299d-181e-4436-824f-a995c9317a92', $q$Streamlined contract close$q$, $q$Reps combine proposals with built-in e-signatures to move a prospect from final review to signed deal without switching tools.$q$, $q$Account executives and closers$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('95f3299d-181e-4436-824f-a995c9317a92', $q$Team$q$, $q$Starting around $19-29 per user/month$q$, $q$Annual (monthly billing may cost more)$q$, $q$["Proposal templates and editor","E-signatures","Basic analytics","CRM integrations","Multiple team members"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('95f3299d-181e-4436-824f-a995c9317a92', $q$Business$q$, $q$Custom quote$q$, $q$Annual$q$, $q$["Approval workflows","Advanced permissions and content locking","Advanced analytics and reporting","Priority support","Dedicated onboarding"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('95f3299d-181e-4436-824f-a995c9317a92', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Proposify is a cloud-based proposal management platform built to help sales teams create, send, track, and close business proposals faster. Rather than assembling documents from scratch in a word processor, teams design reusable templates and content blocks that can be mixed and matched for each new deal, cutting down the time it takes to produce a polished, on-brand proposal.$q$, $q$Beyond document creation, Proposify positions itself as a workflow tool for the entire proposal lifecycle. Once a proposal is sent, the platform provides visibility into what happens next: whether the recipient opened it, how long they spent on each section, and when they signed. That tracking data is meant to give sales reps a clearer read on deal momentum instead of waiting in the dark for a reply.$q$, $q$The product also includes electronic signature capture, approval workflows for internal sign-off before a proposal goes out, and integrations with CRM platforms so proposal activity can be logged alongside other sales data. Pricing is quote-driven around per-user seats, with a free trial available so teams can evaluate the workflow before committing to an annual contract.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('95f3299d-181e-4436-824f-a995c9317a92', $q$who-proposify-is-for$q$, $q$Who Proposify Is For$q$, 2, ARRAY[$q$Proposify is best suited to sales-driven organizations that send a meaningful volume of proposals every month and want to standardize how those documents look and behave. Agencies, consultancies, managed service providers, and B2B sales teams that repeatedly quote similar services are a natural fit because they can build a library of templates once and reuse it across many deals.$q$, $q$It also appeals to sales leaders who want more control and visibility over the proposal stage of the pipeline. Features like approval workflows, content locking, and viewer analytics give managers a way to enforce pricing consistency and branding while still letting individual reps personalize each document for their prospect.$q$, $q$Teams that already use a CRM and want proposal data folded into their broader sales reporting will benefit most from the platform's integrations, since deal status and proposal engagement can be viewed together rather than as separate systems.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('95f3299d-181e-4436-824f-a995c9317a92', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Solo freelancers or very small businesses that send only a handful of proposals a month may find the per-user subscription cost hard to justify compared to simpler document tools or a well-formatted PDF. If proposal volume is low and templates rarely change, the return on a dedicated platform is smaller.$q$, $q$Organizations that need deep, industry-specific quoting logic, such as complex configure-price-quote scenarios with heavy product catalogs and pricing rules, may outgrow Proposify's proposal-focused feature set and need a more specialized CPQ system instead.$q$, $q$Teams looking for an all-in-one contract lifecycle management suite with extensive legal redlining, clause libraries, and obligation tracking may also find Proposify lighter than dedicated CLM software, since its core strength is the proposal and quote stage rather than long-term contract governance.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('95f3299d-181e-4436-824f-a995c9317a92', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At its core, Proposify offers a drag-and-drop document editor with a library of customizable templates, reusable content blocks, and interactive pricing tables that let prospects choose add-ons or quantities directly inside the proposal. This reduces back-and-forth over pricing changes and keeps every document visually consistent with brand guidelines.$q$, $q$The platform layers analytics on top of the document itself, showing when a proposal was opened, how much time was spent per page, and which sections drew the most attention. Built-in legally binding e-signatures let recipients approve and sign without leaving the document, and automated reminders help reps follow up at the right moment instead of guessing.$q$, $q$For teams that need governance, Proposify includes approval workflows so proposals with non-standard pricing or terms can be routed to a manager before sending, along with role-based permissions and locked content sections. Integrations with common CRMs and payment tools help sync proposal data with the rest of the sales stack and, in some cases, let clients pay directly upon signing.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('95f3299d-181e-4436-824f-a995c9317a92', $q$the-proposify-experience$q$, $q$The Proposify Experience$q$, 2, ARRAY[$q$New users typically start from the template library, adapting an existing layout rather than building a proposal from a blank page. The editor is visual and modular, so adding a case study, updating a pricing table, or swapping in a new cover image tends to feel more like arranging blocks than formatting a document, which shortens the learning curve for non-designers on the sales team.$q$, $q$Once a proposal is sent, the experience shifts toward monitoring. Reps get notified as prospects open and interact with the document, and the analytics view gives a sense of engagement that a plain emailed PDF never could. Combined with e-signature, the path from final review to signed deal often happens inside a single link rather than a chain of email attachments.$q$, $q$Administrators generally spend more time upfront setting up brand assets, template structures, and approval rules, which pays off over time as reps reuse that foundation deal after deal. Teams that invest in a clean template library tend to report a smoother day-to-day experience than those who treat the tool as a one-off document generator.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('95f3299d-181e-4436-824f-a995c9317a92', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
